import json, importlib.util, os, sys

spec = importlib.util.spec_from_file_location('validator_cli', '/tool_library/improved_stl_validator_ascii_binary_cli.py')
mod = importlib.util.module_from_spec(spec)
spec.loader.exec_module(mod)

results = []
for i in range(1, 21):
    fn = f'supplier_{i:03d}.stl'
    res = mod.validate_file(fn)
    entry = {'file': fn, 'valid': bool(res.get('valid', False))}
    if not entry['valid']:
        reasons = []
        issues = res.get('issues', []) or []
        joined = ' | '.join(issues).lower()
        if 'inverted' in joined or 'orientation' in joined or 'normal' in joined:
            reasons.append('inverted_normals')
        if 'open edge' in joined or 'not a closed solid' in joined or 'boundary' in joined:
            reasons.append('open_mesh')
        if 'non-manifold' in joined:
            reasons.append('non_manifold')
        if 'degenerate' in joined or 'zero area' in joined:
            reasons.append('degenerate_triangles')
        if 'binary' in joined or 'ascii' in joined or 'parse' in joined or 'malformed' in joined or 'no valid faces found' in joined:
            reasons.append('parse_error')
        if 'volume' in joined:
            reasons.append('zero_or_invalid_volume')
        if not reasons:
            reasons.append('validation_failed')
        entry['reason'] = '+'.join(sorted(set(reasons)))
    results.append(entry)

with open('validation_report.json', 'w') as f:
    json.dump({'results': results}, f)

print(json.dumps({'results': results}, indent=2))

import json, math, os, struct

EPS = 1e-9
ROUND_DIGITS = 6


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def cross(a, b):
    return (
        a[1]*b[2]-a[2]*b[1],
        a[2]*b[0]-a[0]*b[2],
        a[0]*b[1]-a[1]*b[0],
    )

def dot(a, b):
    return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]

def mag(v):
    return math.sqrt(dot(v, v))

def norm(v):
    m = mag(v)
    if m < EPS:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)

def triangle_area(v1, v2, v3):
    return 0.5 * mag(cross(sub(v2, v1), sub(v3, v1)))

def rvert(v):
    return tuple(round(float(x), ROUND_DIGITS) for x in v)


def parse_ascii(path):
    triangles = []
    issues = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                issues.append('parse_error')
                i += 1
                continue
            verts = []
            i += 1
            while i < len(lines) and lines[i].strip() != 'outer loop':
                i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vp = vline.split()
                            try:
                                verts.append((float(vp[1]), float(vp[2]), float(vp[3])))
                            except Exception:
                                issues.append('parse_error')
                        i += 1
            if len(verts) == 3:
                triangles.append((declared, verts))
            else:
                issues.append('parse_error')
            continue
        i += 1
    if not triangles:
        issues.append('parse_error')
    return triangles, issues


def parse_binary(path):
    triangles = []
    issues = []
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        return [], ['parse_error']
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + count * 50
    if len(data) != expected:
        return [], ['parse_error']
    off = 84
    for _ in range(count):
        vals = struct.unpack('<12fH', data[off:off+50])
        declared = (vals[0], vals[1], vals[2])
        v1 = (vals[3], vals[4], vals[5])
        v2 = (vals[6], vals[7], vals[8])
        v3 = (vals[9], vals[10], vals[11])
        triangles.append((declared, [v1, v2, v3]))
        off += 50
    return triangles, issues


def load_stl(path):
    with open(path, 'rb') as f:
        start = f.read(512)
    try:
        txt = start.decode('utf-8', errors='ignore').lstrip()
    except Exception:
        txt = ''
    size = os.path.getsize(path)
    if size >= 84:
        with open(path, 'rb') as f:
            hdr = f.read(84)
        count = struct.unpack('<I', hdr[80:84])[0]
        if 84 + count * 50 == size:
            return parse_binary(path)
    if txt.startswith('solid'):
        return parse_ascii(path)
    return parse_binary(path)


def validate(path):
    triangles, parse_issues = load_stl(path)
    if not triangles:
        return False, 'parse_error'
    reasons = set(parse_issues)
    edge_count = {}
    dir_edges = {}
    total_area = 0.0
    signed_volume = 0.0
    centroid_sum = [0.0, 0.0, 0.0]
    tri_count = 0
    orientation_issue = False
    normal_issue = False

    for declared, verts in triangles:
        v1, v2, v3 = verts
        total_area += triangle_area(v1, v2, v3)
        tri_count += 1
        centroid_sum[0] += (v1[0]+v2[0]+v3[0]) / 3.0
        centroid_sum[1] += (v1[1]+v2[1]+v3[1]) / 3.0
        centroid_sum[2] += (v1[2]+v2[2]+v3[2]) / 3.0
        c = cross(v2, v3)
        signed_volume += dot(v1, c) / 6.0
        e1 = sub(v2, v1)
        e2 = sub(v3, v1)
        cn = cross(e1, e2)
        area2 = mag(cn)
        if area2 < EPS:
            reasons.add('degenerate_triangles')
            continue
        wn = norm(cn)
        dn = norm(declared)
        if mag(dn) > 0 and dot(dn, wn) < 0.0:
            normal_issue = True
        rv = [rvert(v) for v in verts]
        edges = [(rv[0], rv[1]), (rv[1], rv[2]), (rv[2], rv[0])]
        for a, b in edges:
            key = tuple(sorted((a, b)))
            edge_count[key] = edge_count.get(key, 0) + 1
            dir_edges.setdefault(key, []).append((a, b))

    if tri_count == 0 or total_area < EPS:
        reasons.add('degenerate_triangles')
    open_edges = [k for k, c in edge_count.items() if c == 1]
    nonmanifold = [k for k, c in edge_count.items() if c > 2]
    if open_edges:
        reasons.add('open_mesh')
    if nonmanifold:
        reasons.add('non_manifold')
    for k, dirs in dir_edges.items():
        if len(dirs) == 2:
            if dirs[0] == dirs[1]:
                orientation_issue = True
        elif len(dirs) > 2:
            orientation_issue = True
    if orientation_issue or normal_issue:
        reasons.add('inverted_normals')
    if abs(signed_volume) < EPS and 'open_mesh' not in reasons:
        reasons.add('zero_or_invalid_volume')
    valid = len(reasons) == 0
    if valid:
        return True, None
    priority = ['parse_error', 'degenerate_triangles', 'non_manifold', 'open_mesh', 'inverted_normals', 'zero_or_invalid_volume']
    for p in priority:
        if p in reasons:
            return False, p
    return False, sorted(reasons)[0]

results = []
for i in range(1, 21):
    fn = f'supplier_{i:03d}.stl'
    valid, reason = validate(fn)
    entry = {'file': fn, 'valid': valid}
    if not valid:
        entry['reason'] = reason
    results.append(entry)

with open('validation_report.json', 'w') as f:
    json.dump({'results': results}, f)

print(json.dumps({'results': results}, indent=2))

